mapper.select:
      
      SELECT * FROM (
         SELECT ROWNUM AS RNUM, list.* FROM (
            SELECT * FROM bnc_member m, bnc_company c WHERE
      
	      
	         
	          m.${searchType} like '%'||#{searchKeyword}||'%' AND  
	         
	      
      
         m.memb_id = c.cmpy_memb_id
         ) list
      )
      
      
      
      WHERE RNUM > #{startRowNumber} AND RNUM <= #{endRowNumber}

SELECT * FROM (
   SELECT ROWNUM AS RNUM, list.* FROM (
      SELECT * FROM bnc_member_log log 
      WHERE log.meml_id = #{memb_id}
   ) list
)

mapper.update:
UPDATE bnc_member set
	memb_auth_flag = 'Y'
	WHERE memb_id = #{memb_id}

